ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?terminal_building ?floor_level WHERE {
  ?shops a :Shops .
  ?shopitems a :ShopItems .
  ?shopitems p:hasShops ?shops .
  ?shops p:Terminal_Building ?terminal_building .
  ?shops p:Floor_Level ?floor_level .
  ?shopitems p:ItemName ?itemname_f .
  FILTER(STR(?itemname_f) = "Newspaper")
} }
  component: { SELECT ?floor_level WHERE {
  ?shops a :Shops .
  ?shopitems a :ShopItems .
  ?shopitems p:hasShops ?shops .
  ?shops p:Floor_Level ?floor_level .
  ?shopitems p:ItemName ?itemname_f .
  FILTER(STR(?itemname_f) = "Newspaper")
} }
  component_2: { SELECT ?terminal_building WHERE {
  ?shops a :Shops .
  ?shopitems a :ShopItems .
  ?shopitems p:hasShops ?shops .
  ?shops p:Terminal_Building ?terminal_building .
  ?shopitems p:ItemName ?itemname_f .
  FILTER(STR(?itemname_f) = "Newspaper")
} }
}

PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?itemname ?terminal_building WHERE {
  ?shops a :Shops .
  ?shopitems a :ShopItems .
  ?shopitems p:hasShops ?shops .
  ?shopitems p:ItemName ?itemname .
  ?shops p:Terminal_Building ?terminal_building .
  ?shopitems p:Price ?price_o .
}
ORDER BY DESC(?price_o)
LIMIT 1 }
  component_2: { SELECT ?itemname ?floor_level WHERE {
  ?shops a :Shops .
  ?shopitems a :ShopItems .
  ?shopitems p:hasShops ?shops .
  ?shopitems p:ItemName ?itemname .
  ?shops p:Floor_Level ?floor_level .
  ?shopitems p:Price ?price_o .
}
ORDER BY DESC(?price_o)
LIMIT 1 }
  full: { SELECT ?itemname ?terminal_building ?floor_level WHERE {
  ?shops a :Shops .
  ?shopitems a :ShopItems .
  ?shopitems p:hasShops ?shops .
  ?shopitems p:ItemName ?itemname .
  ?shops p:Terminal_Building ?terminal_building .
  ?shops p:Floor_Level ?floor_level .
  ?shopitems p:Price ?price_o .
}
ORDER BY DESC(?price_o)
LIMIT 1 }
}
